window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2009>1","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"In a particular year, the exchange rate of Naira (\u20a6) varies directly with the Dollar ($). If \u20a61122 is equivalent to $8, find the Naira equivalent of $36.","images":[],"options":{"A":"\u20a68976","B":"\u20a65049","C":"\u20a6140.25","D":"*N31.17"},"answer":"B","explanation":"Let Naira be \u20a6  Dollar be $  \u20a6 \u03b1 $  \u20a6 = K$  where \u20a6 = 1122, $ = 8  1122 = K \u00d7 8  K=11228=140.25  \u2234 \u20a6 = 140.25$  where $ = 36, \u20a6 = ?  \u20a6 = 140.25 \u00d7 36  \u20a6 = 5,049","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>2","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:(312+413)\u00f7(56-23)","images":[],"options":{"A":"114","B":"813","C":"35","D":"47"},"answer":"D","explanation":"(72+133)\u00f7(56-23)=(21 + 266)\u00f7(5 - 46)  =476\u00d761=47","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>3","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"If log2 = x, log3 = y and log7 = z, find, in terms of x, y and z, the value of log(28/3)","images":[],"options":{"A":"2x + y - z","B":"2x + z - y","C":"x + y - 2z","D":"x + z - y"},"answer":"B","explanation":"log(7 \u00d7 43)=log(7 \u00d7 223)   = log7 + log22 - log3   = log7 + 2log2 - log3   = z + 2x - y   = 2x - y + z","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>4","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Arrange the following numbers in descending order of magnitude: 22three, 34five, 21six","images":[],"options":{"A":"21six, 22three, 34five","B":"21six, 34five, 22three","C":"22three, 34five, 21six","D":"34five, 21six, 22three"},"answer":"D","explanation":"(1) 22three = 2 \u00d7 31 + 2 \u00d7 30   = 6 + 2 = 810  (2) 34five = 3 \u00d7 51 + 4 \u00d7 50   = 15 + 4 = 1910  (3) 21six = 2 \u00d7 61 + 1 \u00d7 60   = 12 + 1   = 1310  \u2234 1910 > 1310 > 810  34five > 21six > 22three","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>5","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : SIMPLE INTEREST AND COMPOUND INTEREST","question":"Find the value to which \u20a63,000.00 will amount in 5 years at 6% per annum simple interest.","images":[],"options":{"A":"\u20a63,900.00","B":"\u20a63,750.00","C":"\u20a63,600.00","D":"\u20a63,300.00"},"answer":"A","explanation":"Given: The principal, P = \u20a63,000.00  The Time, T = 5 years  The Rate, R = 6%  The Amount, A = ?  Recall that: Amount = Principal + Simple Interest.  SimpleInterest=PRT100=3000 \u00d7 6 \u00d7 5100=\u20a6900  Amount = \u20a63000 + \u20a6900    = \u20a63900","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>6","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Express the square root of 0.000144 in the standard form.","images":[],"options":{"A":"1.2 \u00d7 10-4","B":"1.2 \u00d7 10-3","C":"1.2 \u00d7 10-2","D":"1.2 \u00d7 10-1"},"answer":"C","explanation":"Given:  0.000144  Let x = 0.000144  Let x = 0.000144  &radic;x&nbsp; = &radic;0.000144&nbsp;  0.000144 = 144 \u00d7 10-6   &radic;x&nbsp; = &radic;144 \u00d7 10-6&nbsp;   = 12 \u00d7 10-3    = 1.2 \u00d7 10-2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>7","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"Two sets are disjoint if,","images":[],"options":{"A":"they are both empty","B":"their union is an empty set","C":"their intersection is an empty set","D":"one of them is a subset of the other"},"answer":"C","explanation":"If two sets are disjoint, they have no intersection.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>8","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Solve the following simultaneous equation:   2x + 3y = 7  x + 5y = 0","images":[],"options":{"A":"x = 5, y = -1","B":"x = 1/5, y = -1","C":"x = -1/5, y = 1","D":"x = -5, y = 1"},"answer":"A","explanation":"Given:  2x + 3y = 7 ......(1)  x + 5y = 0 ......(2)  from (2) x = -5y ......(3)  substitute for x = -5y in (1)  2(-5y) + 3y = 7   -10y + 3y = 7  -7y = 7  y = -1  Substitute for y = -1 in (3)   x = -5(-1) = 5  \u2234 x = 5 and y = -1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>9","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"If32x-23x=4,solveforx","images":[],"options":{"A":"45","B":"413","C":"524","D":"1324"},"answer":"C","explanation":"Given:  32x-23x=4  9 - 46x=4  56x=4  5 = 24x  x=524","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>10","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The following is the graph of a quadratic function. Use it to answer this question.      Find the co-ordinates of point P.","images":["data:image/png;base64,"],"options":{"A":"(0, 4)","B":"(4, 0)","C":"(0, -4)","D":"(-4, 0)"},"answer":"A","explanation":"Given: The graph  From the graph, x = 0 and y = 4  \u2234 P(0, 4)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>11","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The following is the graph of a quadratic function. Use it to answer this question.    Find the values of x when y = 0.","images":["data:image/png;base64,"],"options":{"A":"1, 3","B":"1, 4","C":"2, 3","D":"1, 6"},"answer":"B","explanation":"When y = 0, from the graph, the curve passes the x-axis at 1 and 4 respectively i.e (1, 4)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>12","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Five bottles of Fanta and two packets of biscuits cost Gh\u2284 6.00. Three bottles of Fanta and four packes of biscuits ost Gh\u2284 5.00. Find the cost of a bottle of Fanta.","images":[],"options":{"A":"Gh\u2284 0.50","B":"Gh\u2284 1.00","C":"Gh\u2284 1.50","D":"Gh\u2284 5.00"},"answer":"B","explanation":"Given: 5 bottles of Fanta + 2 packets of biscuits = Gh\u2284 6.00  3 bottles of Fanta + 4 packets of biscuits = Gh\u22845.00  Let x = Fanta and y = biscuits  5x + 2y = 6 ......(1) \u00d7 3  3x + 4y = 5 ......(2) \u00d7 5  15x + 6y = 18 ....(3)  15x + 20y = 25 ......(4)  Subtract (4) from (3)  0x + (-14y) = -7  -14y = -7  2y = 1  y = 1/2  substitute for y = 1/2 in (1)  5x + 2( 1/2 ) = 6  5x + 1 = 6  5x = 5  x = 1  A bottle of Fanta = x = Gh\u22841.00","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>13","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"If (2x + 3)3 = 125, find the value of x","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"A","explanation":"Given: (2x + 3)3 = 125  Raise both sides to the power of 1/3  (2x + 3)3\u00d71/3 = (125)1/3  2x + 3 = 5  2x = 5 - 3  2x = 2   x = 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>14","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorize x3 - 2x - 3xy + 6y completely.","images":[],"options":{"A":"(x - 2)(3x - y)","B":"(x - 3y)(x - 2)","C":"(x - 3y)(x + 3y)","D":"(3x + y)(x - 2)"},"answer":"B","explanation":"Given: To factorize x2 - 2x - 3xy + 6y  x2 - 2x - 3xy + 6y= x(x - 2) - 3y(x - 2)  (x - 3y)(x - 2)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>15","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Whichofthefollowingillustratesthesolutionof3x + 42x+3?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"Given:3x + 42x+3  3x + 4  3x - 2x  x","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>16","subject":"Mathematics","year":"2009","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The diameter of a bicycle wheel is 42cm. If the wheel makes 16 complete revolution, what will be the total distance covered by the wheel?   [Take \u03c0 = 22/7}","images":[],"options":{"A":"672 cm","B":"1056 cm","C":"2112 cm","D":"4224 cm"},"answer":"C","explanation":"Given: The diameter of a bicycle wheel = 42cm.  The number of revolutions = 16   The distance covered in a revolution = Circumference of the wheel = \u03c0D   =227\u00d742= 132cm  For 16 revolutions = 132 \u00d7 16 = 2112cm.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>17","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"PQRS is a trapezium. QR//PS, /PQ/ = 5cm, /QR/ = 6cm, /PS/ = 10cm and angle QPS = 42\u00b0.  Use the information to answer this question      Calculate the perpendicular distance between the parallel sides.","images":["data:image/png;base64,"],"options":{"A":"3.35 cm","B":"3.72 cm","C":"4.50 cm","D":"4.62 cm"},"answer":"A","explanation":"Given: The diagram  hsin42\u00b0=5sin90\u00b0  h=5 \u00d7 sin 42\u00b0sin90\u00b0=5 \u00d7 0.6691.0=3.35cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>18","subject":"Mathematics","year":"2009","type":"Objective","topic":"MENSURATION : AREAS","question":"PQRS is a trapezium. QR//PS, /PQ/ = 5cm, /QR/ = 6cm, /PS/ = 10cm and angle QPS = 42\u00b0.  Use the information to answer this question    Calculate, correct to the nearest cm2, the area of the trapezium.","images":["data:image/png;base64,"],"options":{"A":"27cm2","B":"30cm2","C":"36cm2","D":"37cm2"},"answer":"A","explanation":"Recall,AreaofTrapezium=12(a+b)h  A = 1/2 (6+10)3.35 = 1/2 \u00d7 16 \u00d7 3.35  A = 8 \u00d7 3.35  A = 26.8cm2 \u2248 27cm2 (N.cm2)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>19","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, /TP/ = 12cm and it is 6cm from O, the centre of the circle. Calculate \u2220TOP.","images":["data:image/png;base64,"],"options":{"A":"120\u00b0","B":"90\u00b0","C":"60\u00b0","D":"45\u00b0"},"answer":"B","explanation":"Given: (1) The diagram    (2) The distance of the cord from the centre, O = 6cm   Draw the given triangles (right- angled) in the circle     tan\u03b8 = 6/6   \u03b8 = tan-1(1)   \u03b8 = 45\u00b0   2\u03b8 =  2\u03b8  = 90\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>20","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The interior angles of a pentagon are (2x + 5)\u00b0, (x + 20)\u00b0, x\u00b0, (3x - 20)\u00b0 and (x + 15)\u00b0. Find the a value of x.","images":[],"options":{"A":"80\u00b0","B":"70\u00b0","C":"65\u00b0","D":"40\u00b0"},"answer":"C","explanation":"Given: The values of the angles (interior) of the pentagon   Conventionally, the sum of the interior angles of a pentagon = 540\u00b0  \u2234 (2x + 5)\u00b0 + (x + 20)\u00b0 + x\u00b0 + (3x - 20)\u00b0 + (x + 15)\u00b0 = 540\u00b0  8x + 20 = 540  x = 65\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>21","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, IG is parallel to JE, \u2220JEF = 120\u00b0 and \u2220FHG = 130\u00b0.  Find the angle marked t.","images":["data:image/png;base64,"],"options":{"A":"40\u00b0","B":"70\u00b0","C":"80\u00b0","D":"100\u00b0"},"answer":"B","explanation":"Given: The diagram in the question.    (1) JE to meet FH at O  \u2192 120\u00b0 + \u2220FEO = 180\u00b0 (angle on a straight line)  180\u00b0 - 120\u00b0 = \u2220FEO  \u2220FEO = 60\u00b0    (2) \u2220IHO + \u2220OHG = 180\u00b0 (angle on a straight line)  \u2220IHO + 130\u00b0 = 180\u00b0  \u2220IHO = 180\u00b0 - 130\u00b0  \u2220IHO = 50\u00b0    (3) \u2220EOF = \u2220IHO (corresponding angles)  \u2234 \u2220EOF = \u2220IHO = 50\u00b0    (4) t + 60\u00b0 + 50\u00b0 = 180\u00b0 (sum of angles in a triangle)  t + 110 \u00b0 = 180\u00b0  t = 180\u00b0 - 110\u00b0 = 70\u00b0  \u2234 t = 70\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>22","subject":"Mathematics","year":"2009","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"If M and N are two fixed points in a plane, find the locus L = {P : PM = PN}","images":[],"options":{"A":"A line equal to MN","B":"A line parallel to MN","C":"Perpendicular bisector of MN","D":"A circle centre P, radius MN"},"answer":"C","explanation":"The Locus is a perpendicular bisector of MN.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>23","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Find the value of x in the diagram.","images":["data:image/png;base64,"],"options":{"A":"50\u00b0","B":"30\u00b0","C":"22\u00b0","D":"17\u00b0"},"answer":"D","explanation":"Given: The diagram in the question (a polygon)  Conventionally, the sum of the exterior angle of a polygon = 360\u00b0  x + 64 + 2x + 3x - 54 + 5x + 2x + 4x + 3x + 10 = 360\u00b0  20x + 20 = 360  20x = 340  x = 17\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>24","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"In the diagram, /SQ/ = 4cm, /PT/ = 7cm, /TR/ = 5cm and ST//OR. If /SP/ = x cm.  Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"5.6","B":"6.5","C":"6.6","D":"6.8"},"answer":"A","explanation":"Given: The diagram  \u21d2 We have similar triangles in the diagram, \u0394PST and \u0394PQR  \u22344 + xx=7 + 57  Cross multiply  7(4 + x) = x(7 + 5)  28 + 7x = 12x  28 = 5x  x = 5.6","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>25","subject":"Mathematics","year":"2009","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Giventhatsin60\u00b0=&radic;3&nbsp;2andcos60\u00b0=12.Evaluate:  1 - sin60\u00b01 + cos60\u00b0","images":[],"options":{"A":"2+&radic;3&nbsp;3","B":"1-&radic;3&nbsp;3","C":"1+&radic;3&nbsp;3","D":"2-&radic;3&nbsp;3"},"answer":"D","explanation":"Given:sin60\u00b0=&radic;3&nbsp;2andcos60\u00b0=12  1 - sin60\u00b01 + cos60\u00b0=1 - &radic;3&nbsp;/21 + 1/2  =2 - &radic;3&nbsp;2\u00f732   =2 - &radic;3&nbsp;2\u00d723 =2 - &radic;3&nbsp;3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>26","subject":"Mathematics","year":"2009","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"Use the diagram below to answer this question.      Find the bearing of X from Y","images":["data:image/png;base64,"],"options":{"A":"300\u00b0","B":"240\u00b0","C":"120\u00b0","D":"60\u00b0"},"answer":"B","explanation":"Given: The diagram in the question.    The bearing of X from Y = 180\u00b0 + 60\u00b0   = 240\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>27","subject":"Mathematics","year":"2009","type":"Objective","topic":"VECTORS AND TRANSFORMATION : VECTORS IN A PLANE","question":"Use the diagram below to answer this question.    If /XY/ = 50m, how far east of X is Y?","images":["data:image/png;base64,"],"options":{"A":"25.5m","B":"40.6m","C":"40.8m","D":"43.3m"},"answer":"D","explanation":"cos30\u00b0=P50  P=50\u00d70.8660=43.3m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>28","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"In an examination, Kofi scored x% in Physics, 50% in Chemistry and 70% in Biology. If his mean score for the three subjects was 55%, find x.","images":[],"options":{"A":"40","B":"45","C":"55","D":"60"},"answer":"B","explanation":"Given: The respective scores of Kofi in 3 courses.  - Physics : x %  - Chemistry : 50%  - Biology: 70%   - The mean score for the three subjects = 55%  Recallthat:Mean-x-=Summation of marks(e.g scores)Numbers of marks(e.g scores)   55 =x + 50 + 703  55=120 + x3  165 = 120 + x  x = 45%","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>29","subject":"Mathematics","year":"2009","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"What is the median of the following scores: 22, 41, 35, 63, 82, 74?","images":[],"options":{"A":"82","B":"52","C":"49","D":"22"},"answer":"B","explanation":"Given: The \u21d2 22, 41, 35, 63, 82, 74.  Arrange in ascending order: 22, 35, 41, 63, 74, 82  Median=41 + 632 =1042=52","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>30","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express 2.7864 \u00d7 10-3 to two significant figures.","images":[],"options":{"A":"0.28","B":"0.27","C":"0.0028","D":"0.0027"},"answer":"C","explanation":"Given: 2.7864 \u00d7 10-3  In two significant figures, we have: 2.8 \u00d7 10-3 = 0.0028.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>31","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"If92x=13(27x),findx","images":[],"options":{"A":"2","B":"1","C":"-1","D":"-2"},"answer":"C","explanation":"Given: 92x=13(27x)  (32)2x = 3-1(33x)  34x = 3-1 \u00d7 33x  34x = 3-1 + 3x  Equate the powers   4x = -1 + 3x  x = -1","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>32","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"If 85% of x is \u20a63,230, what is the value of x?","images":[],"options":{"A":"\u20a62745.50","B":"\u20a63714.50","C":"\u20a63800.00","D":"\u20a64845.00"},"answer":"C","explanation":"Given: 85% of x = \u20a63230  \u223485100\u00d7x=3230  85x = 323000  x=32300085=\u20a63800","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>33","subject":"Mathematics","year":"2009","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The capacity of a water tank is 1,800 litres. If the tank is in form of a cuboid with base 600cm by 150cm, find the height of the tank.","images":[],"options":{"A":"2cm","B":"20cm","C":"200cm","D":"2000cm"},"answer":"B","explanation":"Given:  (1) The volume of a water tank with a cuboidal base = 1800L  (2) The dimension of the base = 600cm by 150cm  Recall that: 1000cm3 = 1 Litre :1800L = (1800 \u00d7 1000)cm3  Volume = Base area \u00d7 Height  \u2234 (1800 \u00d7 1000) cm3 = 600cm \u00d7 150cm \u00d7 Height (in cm)  1800 cm3 = 90cm2 \u00d7 Height (in cm)  1800cm = 90 \u00d7 Height (in cm)  20 = Height (in cm)  Height = 20cm.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>34","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"An arc of a circle subtends and angle of 60\u00b0 at the centre. If the radius of the circle is 3cm, find, in terms of \u03c0, the length of the arc.","images":[],"options":{"A":"\u03c0 cm","B":"2\u03c0cm","C":"3\u03c0cm","D":"6\u03c0cm"},"answer":"A","explanation":"Given: (1) The angle, \u03b8 subtended at the centre = 60\u00b0   (2) The radius, r of the circle = 3cm   (3) The length, L of the arc is unknown  Recall that: L=\u03b8360\u00d72\u03c0r  L=60360\u00d72\u03c0\u00d73=16\u00d76\u03c0=\u03c0cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>35","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Solve:2x + 16-3x - 14=0","images":[],"options":{"A":"1","B":"1/5","C":"-1/5","D":"-1"},"answer":"A","explanation":"Given:Tosolve2x+16-3x-14=0  4(2x + 1) - 6(3x - 1)24=0  8x + 4 - 18x + 6 = 0   -10x + 10 = 0  -10x = -10  x = 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>36","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"If x is a positive integer, list the values of x which satisfy the inequalities 3x - 4  0.","images":[],"options":{"A":"{1, 2, 3}","B":"{2, 3}","C":"{2, 3, 4}","D":"{2, 3, 4, 5}"},"answer":"B","explanation":"Given: (1) x is a positive integer  (2) 3x - 4  (3) x - 1 > 0  from 2:  3x  x  x>1   x = {2,3}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>37","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"If c and k are the roots of 6 - x - x2 = 0, find c + k.","images":[],"options":{"A":"2","B":"1","C":"-1","D":"-3"},"answer":"C","explanation":"Given: c and k as the roots of 6 - x - x2.  a = -1, b = -1, c = 6  Recall, sum of roots for a Quadratic Equation, C + K = -b/a  C + K = -(-1)/-1 = 1/-1 = -1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>38","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, angle 200\u00b0 is subtended at the centre of the circle. Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"30\u00b0","B":"50\u00b0","C":"80\u00b0","D":"100\u00b0"},"answer":"B","explanation":"Given: The diagram below:     (1) \u2220 POR = 360 - 200 = 160\u00b0   (2)\u2220PQR=160\u00b02=80\u00b0(Anglesubstendedatthecentreistwicesubtendedatotherpointsonthe( circumference)   (3) x + 200 + 30 + 80 = 360\u00b0 (angles in a quadrilateral)    x + 310\u00b0 = 360\u00b0    x = 50\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>39","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"Each of the interior angles of a regular polygon is 140\u00b0. Calculate the sum of all the interior angles of the polygon.","images":[],"options":{"A":"1080\u00b0","B":"1260\u00b0","C":"1800\u00b0","D":"2160\u00b0"},"answer":"B","explanation":"Given: The value of each interior angle = 140\u00b0  Recallthat:Thevalueofeachinteriorangle=180n - 360n  \u2234140=180n - 360n  140n = 180n - 360  140n - 180n = -360  -40n = -360  n = 9 (n = number of sides)  The sum of the interior angles = 180n - 360 = 180(9) - 360 = 1620 - 360 = 1260\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>40","subject":"Mathematics","year":"2009","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A bucket holds 10 litres of water. How many buckets of water will fill a reservoir of size 8m \u00d7 7m \u00d7 5m. ( 1 litre = 1000cm3)","images":[],"options":{"A":"28","B":"280","C":"2800","D":"28000"},"answer":"D","explanation":"Given: (1) The capacity of the bucket = 10 litres  (2) 1 litre = 1,000cm3  \u2234 10 litres = 10,000cm3  (3) The dimension of the reservoir = 8m \u00d7 7m \u00d7 5m.  The volume of the reservoir = 8m \u00d7 7m \u00d7 5m = 280m3  Also: 1cm3 = 10-6m3  10,000 cm3 = x m3  x = 10-2m3  \u2234 The capacity of the bucket (in m3 ) = 10-2m3  The volume of the reservoir = 280m3  The number of the bucket that can fill the reservoir = 280/10-2 = 28,000","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2009>41","subject":"Mathematics","year":"2009","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A box contains black, white and red identical balls. The probability of picking a black ball at random from the box is 3/10 and the probability of picking a white ball at random is 2/5. If there are 30 balls in the box, how many of them are red?","images":[],"options":{"A":"3","B":"7","C":"9","D":"12"},"answer":"C","explanation":"Given: (1) The probability of picking a white ball = 2/5  (2) The probability of picking a black ball = 3/10  (3) The number of balls = 30  (4) The number of red balls is unknown.  Let the number of black balls be x  \u2234 x/30 = 3/10  10x = 90   x = 9  Let the number of white balls be y   y30=25  5y = 60  y = 12  \u2234 30 = N(Red) + N(Black) + N(White)  30 = N(Red) + 9 + 12  30 = N(Red) + 21  N(Red) = 9","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>42","subject":"Mathematics","year":"2009","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart shows the distribution of 4320 students who graduated from four Departments in a University. Use the information to answer this question      How many students graduated from the Science Department?","images":["data:image/png;base64,"],"options":{"A":"840","B":"864","C":"920","D":"960"},"answer":"B","explanation":"Given: (1) The total students = 4320  (2) The angle in the arts sector = 100\u00b0  (3) The angle in the medicine sector = 80\u00b0  (4) The angle in the education sector = 108\u00b0  (5) The angle in the science sector = x  Recall: The total angles in the sector = 360\u00b0 (angle in a circle)  \u2234 100 + 80 + 108 + x = 360\u00b0  288 + x = 360;  x = 360 - 288 = 72\u00b0  The number of students that graduated from the science department  =Angle in the science sector360\u00d7Total students  =72360\u00d74320=15\u00d74320=864students","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>43","subject":"Mathematics","year":"2009","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The pie chart shows the distribution of 4320 students who graduated from four Departments in a University. Use the information to answer this question    If a student is picked at random from the four Departments, what is the probability that he is not from the Education Department?","images":["data:image/png;base64,"],"options":{"A":"3/10","B":"2/9","C":"5/18","D":"7/10"},"answer":"D","explanation":"The probability that a student picked at random is not from Education Department = 1 - probability that a student picked at random is from Education Department.  \u2234Probabilitythatastudentpickedatrandomisfromeducation=Number of students in the Education DepartmentTotal students  NumberofstudentsintheEducationDepartment=108360\u00d74320  =620\u00d74320  = 1296    Probability(Education)=12964320=310  Probability(NotEducation)=1-310=710","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>44","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:12&radic;32&nbsp;-&radic;18&nbsp;+&radic;2&nbsp;","images":[],"options":{"A":"0","B":"&radic;2&nbsp;","C":"2&radic;2&nbsp;","D":"4&radic;2&nbsp;"},"answer":"A","explanation":"Given:  To simplify:12&radic;32&nbsp;-&radic;18&nbsp;+&radic;2&nbsp;  12&radic;32&nbsp;-&radic;18&nbsp;+&radic;2&nbsp;=12&radic;162&nbsp; -&radic;9\u00d72&nbsp;+&radic;2&nbsp;   = 1/2 \u00d7 &radic;16&nbsp; \u00d7 &radic;2&nbsp; - &radic;9&nbsp; \u00d7 &radic;2&nbsp; + &radic;2&nbsp;   = 1/2 \u00d7 4 \u00d7 &radic;2&nbsp; - 3 \u00d7 &radic;2&nbsp; + &radic;2&nbsp;   = 2&radic;2&nbsp; - 3&radic;2&nbsp; + &radic;2&nbsp;   = 0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>45","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"From the diagram, which of the following statements is/are correct?  I. XQ is a radius of a circle radius centre Q.  II. /XQ/ = /QY/  III. /QX/ = /XY/","images":["data:image/png;base64,"],"options":{"A":"I only","B":"I and II only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"XQ is a radius of a circle radius centre Q &  /XQ/ = /QY/ are the only correct answers.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>46","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Find the value of x in the diagram.","images":["data:image/png;base64,"],"options":{"A":"50\u00b0","B":"60\u00b0","C":"70\u00b0","D":"80\u00b0"},"answer":"D","explanation":"Given: The diagram in the question    (1) Letter the diagram above.  (2) \u2220EXO = \u2220DOX = 30\u00b0 (alternate angles)  (3) \u2220BAO = \u2220AOD = x\u00b0 (alternate angles)  (4) \u2220COX + \u2220DOX = 180\u00b0 (angle on a straight line)  \u2234 \u2220COX + 30\u00b0 = 180\u00b0  \u2220COX = 150\u00b0  (5) \u2220COX + \u2220COA = 250  \u2234\u2220COA = 100  \u2220COA + x = 180\u00b0 (angle on a straight line)   100 + x = 180\u00b0  x = 80\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>47","subject":"Mathematics","year":"2009","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"The angles of a triangle are (x + 10)\u00b0, (2x - 40)\u00b0 and (3x - 90)\u00b0. Which of the following accurately describes the triangle?","images":[],"options":{"A":"It is a scalene triangle","B":"It is right angled isosceles triangle","C":"It is an equilateral triangle","D":"It is an isosceles triangle but not right angled"},"answer":"C","explanation":"The angles in a given triangle.  (x + 10) + (2x - 40) + (3x - 90) = 180\u00b0 (sum of \u2220 in a triangle)  6x - 120 = 180  6x = 300  x = 50\u00b0  - Each angle = x + 10 = 60\u00b0; 2x - 40 = 2(50) - 40 = 60\u00b0   3x - 90 = 3(50) - 90   = 150 - 90 = 60\u00b0  - Each angle is equal to the other = 60\u00b0 (a feature of an equilateral triangle).","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>48","subject":"Mathematics","year":"2009","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"Which shaded region in the following diagram represents (P \u222a Q) \u2229 R?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"Given to find the image that matches :(P \u222a Q) \u2229 R. Option C conforms with this","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2009>49","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify: (x - 3y)2 - (x + 3y)2","images":[],"options":{"A":"2(x + 3y)","B":"(2x - 3y)","C":"-12xy","D":"6xy"},"answer":"C","explanation":"Given: To simplify (x - 3y)2 - (x + 3y)2  Let x - 3y = a and x + 3y = b  \u2234 (x - 3)2 - (x + 3y)2 = a2 - b2  Recall that: a2 - b2 = (a + b)(a - b)   Difference of two squares  \u2234 = (x - 3y + x + 3y)(x - 3y - (x + 3y))= (2x)(x - 3 - x - 3y)= (2x)(-6y)= -12xy","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2009>50","subject":"Mathematics","year":"2009","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Find the quadratic equation whose roots are -1/2 and 3.","images":[],"options":{"A":"2x2 - 2x + 3 = 0","B":"2x2 - 2x - 3 = 0","C":"2x2 - 5x + 3 = 0","D":"2x2 - 5x - 3 = 0"},"answer":"D","explanation":"Given: The roots of a quadratic equation: -1/2 and 3  Let \u03b1 = -1/2 and \u03b2 = 3  Recall that: (x - \u03b1)(x - \u03b2) = x2 - (\u03b1 + \u03b2)x + \u03b1\u03b2 = 0   x2 - (\u03b1 + \u03b2) x + \u03b1\u03b2 = x2 - (-1/2 + 3)x + (-1/2)(3)   =x2-(52)x-32  =x2-52x-32  2x2 - 5x - 3 = 0","marks":"1","difficulty":"2"}];